const response = $json;
const channel = $('Loop Channels').first().json;
const messages = response.value || [];
if (!messages.length) {
  return [];
}
return messages.map(msg => ({
  json: {
    ...msg,
    _channel: channel,
    _teamId: '2f7e4d78-5cc0-4b00-bb44-372596f96fcf'
  }
}));

const msg = $json;
const channel = msg._channel;
const replyCount = parseInt($response.body || '0') || 0;

return {
  json: {
    messageId: msg.id,
    channelId: channel.channelId,
    country: channel.country,
    entorno: channel.entorno,
    createdDateTime: msg.createdDateTime || '',
    authorId: msg.from?.user?.id || '',
    authorDisplayName: msg.from?.user?.displayName || '',
    messageType: msg.messageType || 'message',
    reactionsJson: JSON.stringify(msg.reactions || []),
    reactionCount: (msg.reactions || []).length,
    replyCount: replyCount,
    lastModifiedDateTime: msg.lastModifiedDateTime || msg.createdDateTime || '',
    fetchedAt: new Date().toISOString()
  }
};
